      "affected_versions": "Kubernetes v1.28.0–v1.28.2, v1.27.0–v1.27.6, v1.26.0–v1.26.9, v1.25.0–v1.25.14, and earlier unsupported versions",
      "vulnerability_type": "Privilege escalation via Kubernetes API server proxy handling of aggregated API servers",
