      "remediation": "Upgrade to Kubernetes v1.28.2, v1.27.5, v1.26.8, or v1.25.13 or later. Review and harden admission webhook configurations."
    },
    {
      "advisory_id": "CVE-2022-3172",
      "affected_versions": "Kubernetes v1.25.0–v1.25.2, v1.24.0–v1.24.6, v1.23.0–v1.23.12, and earlier",
      "vulnerability_type": "Authentication bypass in aggregated API servers via improper handling of user impersonation headers",
      "remediation": "Upgrade to Kubernetes v1.25.3, v1.24.7, v1.23.13, or later. Restrict access to aggregated API servers and validate impersonation headers."
    },
    {
      "advisory_id": "CISA-K8S-2023-01",
      "affected_versions": "Multiple Kubernetes versions prior to v1.27.5",
      "vulnerability_type": "Multiple high-severity vulnerabilities in admission webhooks and API server components",
      "remediation": "Apply the latest Kubernetes security patches as recommended by CISA. Audit webhook configurations and enforce RBAC least privilege."
    }
  ]
